206: bool HeaderUtility::headerNameIsValid(absl::string_view header_key) {
207:   if (!header_key.empty() && header_key[0] == ':') {
208: #ifdef ENVOY_NGHTTP2
209:     if (!Runtime::runtimeFeatureEnabled(
210:             "envoy.reloadable_features.sanitize_http2_headers_without_nghttp2")) {
211:       // For HTTP/2 pseudo header, use the HTTP/2 semantics for checking validity
212:       return nghttp2_check_header_name(reinterpret_cast<const uint8_t*>(header_key.data()),
213:                                        header_key.size()) != 0;
214:     }
215: #endif
216:     header_key.remove_prefix(1);
217:     if (header_key.empty()) {
218:       return false;
219:     }
220:   }
221:   // For all other header use HTTP/1 semantics. The only difference from HTTP/2 is that
222:   // uppercase characters are allowed. This allows HTTP filters to add header with mixed
223:   // case names. The HTTP/1 codec will send as is, as uppercase characters are allowed.
224:   // However the HTTP/2 codec will NOT convert these to lowercase when serializing the
225:   // header map, thus producing an invalid request.
226:   // TODO(yanavlasov): make validation in HTTP/2 case stricter.
227:   bool is_valid = true;
228:   for (auto iter = header_key.begin(); iter != header_key.end() && is_valid; ++iter) {
229:     is_valid &= testCharInTable(kGenericHeaderNameCharTable, *iter);
230:   }
231:   return is_valid;
232: }
