235:   const bool edge_request = !internal_request && config.useRemoteAddress();
236: 
237:   // If internal request, set header and do other internal only modifications.
238:   if (internal_request) {
239:     request_headers.setReferenceEnvoyInternalRequest(
240:         Headers::get().EnvoyInternalRequestValues.True);
241:   } else {
242:     cleanInternalHeaders(request_headers, edge_request, route_config.internalOnlyHeaders());
243:   }
244: 
245:   if (config.userAgent()) {
246:     request_headers.setEnvoyDownstreamServiceCluster(config.userAgent().value());
247:     const HeaderEntry* user_agent_header = request_headers.UserAgent();
248:     if (!user_agent_header || user_agent_header->value().empty()) {
249:       // Following setReference() is safe because user agent is constant for the life of the
250:       // listener.
251:       request_headers.setReferenceUserAgent(config.userAgent().value());
252:     }
253: 
254:     // TODO(htuch): should this be under the config.userAgent() condition or in the outer scope?
255:     if (!local_info.nodeName().empty()) {
256:       // Following setReference() is safe because local info is constant for the life of the server.
257:       request_headers.setReferenceEnvoyDownstreamServiceNode(local_info.nodeName());
258:     }
259:   }
260: 
261:   if (!config.via().empty()) {
262:     Utility::appendVia(request_headers, config.via());
263:   }
264: 
265:   // If we are an external request, AND we are "using remote address" (see above), we set
266:   // x-envoy-external-address since this is our first ingress point into the trusted network.
267:   if (edge_request && final_remote_address->type() == Network::Address::Type::Ip) {
268:     request_headers.setEnvoyExternalAddress(final_remote_address->ip()->addressAsString());
269:   }
270: 
271:   // Generate x-request-id for all edge requests, or if there is none.
272:   if (config.generateRequestId()) {
273:     auto rid_extension = config.requestIDExtension();
274:     // Unconditionally set a request ID if we are allowed to override it from
275:     // the edge. Otherwise just ensure it is set.
276:     const bool force_set = !config.preserveExternalRequestId() && edge_request;
277:     rid_extension->set(request_headers, force_set);
278:   }
279: 
280:   if (connection.connecting() && request_headers.get(Headers::get().EarlyData).empty()) {
281:     // Add an Early-Data header to indicate that this is a 0-RTT request according to
282:     // https://datatracker.ietf.org/doc/html/rfc8470#section-5.1.
283:     HeaderString value;
284:     value.setCopy("1");
285:     request_headers.addViaMove(HeaderString(Headers::get().EarlyData), std::move(value));
286:   }
287:   mutateXfccRequestHeader(request_headers, connection, config);
288: 
289:   return {final_remote_address, absl::nullopt};
290: }
