292: void ConnectionManagerUtility::sanitizeTEHeader(RequestHeaderMap& request_headers) {
293:   if (!Runtime::runtimeFeatureEnabled("envoy.reloadable_features.sanitize_te")) {
294:     return;
295:   }
296: 
297:   absl::string_view te_header = request_headers.getTEValue();
298:   if (te_header.empty()) {
299:     return;
300:   }
301: 
302:   // If the TE header contains the "trailers" value, set the TE header to "trailers" only.
303:   std::vector<absl::string_view> te_values = absl::StrSplit(te_header, ',');
304:   for (const absl::string_view& te_value : te_values) {
305:     bool is_trailers =
306:         absl::StripAsciiWhitespace(te_value) == Http::Headers::get().TEValues.Trailers;
307: 
308:     if (is_trailers) {
309:       request_headers.setTE(Http::Headers::get().TEValues.Trailers);
310:       return;
311:     }
312:   }
313: 
314:   // If the TE header does not contain the "trailers" value, remove the TE header.
315:   request_headers.removeTE();
316: }
