800: bool Utility::sanitizeConnectionHeader(Http::RequestHeaderMap& headers) {
801:   static constexpr size_t MAX_ALLOWED_NOMINATED_HEADERS = 10;
802:   static constexpr size_t MAX_ALLOWED_TE_VALUE_SIZE = 256;
803: 
804:   // Remove any headers nominated by the Connection header. The TE header
805:   // is sanitized and removed only if it's empty after removing unsupported values
806:   // See https://github.com/envoyproxy/envoy/issues/8623
807:   const auto& cv = Http::Headers::get().ConnectionValues;
808:   const auto& connection_header_value = headers.Connection()->value();
809: 
810:   StringUtil::CaseUnorderedSet headers_to_remove{};
811:   std::vector<absl::string_view> connection_header_tokens =
812:       StringUtil::splitToken(connection_header_value.getStringView(), ",", false);
813: 
814:   // If we have 10 or more nominated headers, fail this request
815:   if (connection_header_tokens.size() >= MAX_ALLOWED_NOMINATED_HEADERS) {
816:     ENVOY_LOG_MISC(trace, "Too many nominated headers in request");
817:     return false;
818:   }
819: 
820:   // Split the connection header and evaluate each nominated header
821:   for (const auto& token : connection_header_tokens) {
822: 
823:     const auto token_sv = StringUtil::trim(token);
824: 
825:     // Build the LowerCaseString for header lookup
826:     const LowerCaseString lcs_header_to_remove{std::string(token_sv)};
827: 
828:     // If the Connection token value is not a nominated header, ignore it here since
829:     // the connection header is removed elsewhere when the H1 request is upgraded to H2
830:     if ((lcs_header_to_remove.get() == cv.Close) ||
831:         (lcs_header_to_remove.get() == cv.Http2Settings) ||
832:         (lcs_header_to_remove.get() == cv.KeepAlive) ||
833:         (lcs_header_to_remove.get() == cv.Upgrade)) {
834:       continue;
835:     }
836: 
837:     // By default we will remove any nominated headers
838:     bool keep_header = false;
839: 
840:     // Determine whether the nominated header contains invalid values
841:     HeaderMap::GetResult nominated_header;
842: 
843:     if (lcs_header_to_remove == Http::Headers::get().Connection) {
844:       // Remove the connection header from the nominated tokens if it's self nominated
845:       // The connection header itself is *not removed*
846:       ENVOY_LOG_MISC(trace, "Skipping self nominated header [{}]", token_sv);
847:       keep_header = true;
848:       headers_to_remove.emplace(token_sv);
849: 
850:     } else if ((lcs_header_to_remove == Http::Headers::get().ForwardedFor) ||
851:                (lcs_header_to_remove == Http::Headers::get().ForwardedHost) ||
852:                (lcs_header_to_remove == Http::Headers::get().ForwardedProto) ||
853:                !token_sv.find(':')) {
854: 
855:       // An attacker could nominate an X-Forwarded* header, and its removal may mask
856:       // the origin of the incoming request and potentially alter its handling.
857:       // Additionally, pseudo headers should never be nominated. In both cases, we
858:       // should fail the request.
859:       // See: https://nathandavison.com/blog/abusing-http-hop-by-hop-request-headers
860: 
861:       ENVOY_LOG_MISC(trace, "Invalid nomination of {} header", token_sv);
862:       return false;
863:     } else {
864:       // Examine the value of all other nominated headers
865:       nominated_header = headers.get(lcs_header_to_remove);
866:     }
867: 
868:     if (!nominated_header.empty()) {
869:       // NOTE: The TE header is an inline header, so by definition if we operate on it there can
870:       // only be a single value. In all other cases we remove the nominated header.
871:       auto nominated_header_value_sv = nominated_header[0]->value().getStringView();
872: 
873:       const bool is_te_header = (lcs_header_to_remove == Http::Headers::get().TE);
874: 
875:       // reject the request if the TE header is too large
876:       if (is_te_header && (nominated_header_value_sv.size() >= MAX_ALLOWED_TE_VALUE_SIZE)) {
877:         ENVOY_LOG_MISC(trace, "TE header contains a value that exceeds the allowable length");
878:         return false;
879:       }
880: 
881:       if (is_te_header) {
882:         ASSERT(nominated_header.size() == 1);
883:         for (const auto& header_value :
884:              StringUtil::splitToken(nominated_header_value_sv, ",", false)) {
885: 
886:           const absl::string_view header_sv = StringUtil::trim(header_value);
887: 
888:           // If trailers exist in the TE value tokens, keep the header, removing any other values
889:           // that may exist
890:           if (StringUtil::CaseInsensitiveCompare()(header_sv,
891:                                                    Http::Headers::get().TEValues.Trailers)) {
892:             keep_header = true;
893:             break;
894:           }
895:         }
896: 
897:         if (keep_header) {
898:           headers.setTE(Http::Headers::get().TEValues.Trailers);
899:         }
900:       }
901:     }
902: 
903:     if (!keep_header) {
904:       ENVOY_LOG_MISC(trace, "Removing nominated header [{}]", token_sv);
905:       headers.remove(lcs_header_to_remove);
906:       headers_to_remove.emplace(token_sv);
907:     }
908:   }
909: 
910:   // Lastly remove extra nominated headers from the Connection header
911:   if (!headers_to_remove.empty()) {
912:     const std::string new_value = StringUtil::removeTokens(connection_header_value.getStringView(),
913:                                                            ",", headers_to_remove, ",");
914: 
915:     if (new_value.empty()) {
916:       headers.removeConnection();
917:     } else {
918:       headers.setConnection(new_value);
919:     }
920:   }
921: 
922:   return true;
923: }
