461: bool HeaderUtility::shouldCloseConnection(Http::Protocol protocol,
462:                                           const RequestOrResponseHeaderMap& headers) {
463:   // HTTP/1.0 defaults to single-use connections. Make sure the connection will be closed unless
464:   // Keep-Alive is present.
465:   if (protocol == Protocol::Http10 &&
466:       (!headers.Connection() ||
467:        !Envoy::StringUtil::caseFindToken(headers.Connection()->value().getStringView(), ",",
468:                                          Http::Headers::get().ConnectionValues.KeepAlive))) {
469:     return true;
470:   }
471: 
472:   if (protocol == Protocol::Http11 && headers.Connection() &&
473:       Envoy::StringUtil::caseFindToken(headers.Connection()->value().getStringView(), ",",
474:                                        Http::Headers::get().ConnectionValues.Close)) {
475:     return true;
476:   }
477: 
478:   // Note: Proxy-Connection is not a standard header, but is supported here
479:   // since it is supported by http-parser the underlying parser for http
480:   // requests.
481:   if (protocol < Protocol::Http2 && headers.ProxyConnection() &&
482:       Envoy::StringUtil::caseFindToken(headers.ProxyConnection()->value().getStringView(), ",",
483:                                        Http::Headers::get().ConnectionValues.Close)) {
484:     return true;
485:   }
486:   return false;
487: }
