489: Http::Status HeaderUtility::checkRequiredRequestHeaders(const Http::RequestHeaderMap& headers) {
490:   if (!headers.Method()) {
491:     return absl::InvalidArgumentError(
492:         absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Method.get()));
493:   }
494:   bool is_connect = Http::HeaderUtility::isConnect(headers);
495:   if (is_connect) {
496:     if (!headers.Host()) {
497:       // Host header must be present for CONNECT request.
498:       return absl::InvalidArgumentError(
499:           absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Host.get()));
500:     }
501:     if (headers.Path() && !headers.Protocol()) {
502:       // Path and Protocol header should only be present for CONNECT for upgrade style CONNECT.
503:       return absl::InvalidArgumentError(
504:           absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Protocol.get()));
505:     }
506:     if (!headers.Path() && headers.Protocol()) {
507:       // Path and Protocol header should only be present for CONNECT for upgrade style CONNECT.
508:       return absl::InvalidArgumentError(
509:           absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Path.get()));
510:     }
511:   } else {
512:     if (!headers.Path()) {
513:       // :path header must be present for non-CONNECT requests.
514:       return absl::InvalidArgumentError(
515:           absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Path.get()));
516:     }
517:   }
518:   return Http::okStatus();
519: }
